**Stored Procedure: `delete_inactive_users`**

```sql
DELIMITER $$

CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cursor_user_status CURSOR FOR SELECT user_id FROM users WHERE status = 'Inactive';
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;

    START TRANSACTION;

    -- Delete inactive users
    DELETE FROM users WHERE status = 'Inactive';

    -- Log the deletion in the status_log table
    INSERT INTO status_log (user_id, status, modification_date)
    SELECT user_id, 'Inactive', NOW()
    FROM users
    WHERE status = 'Inactive';

    COMMIT;

    -- Optional: Rollback if an error occurs
    -- ROLLBACK;

    -- Optional: Display a message
    SELECT 'Users with "Inactive" status have been successfully deleted.' AS message;
END $$

DELIMITER ;
```

