CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        -- Rollback the transaction in case of error
        ROLLBACK;
        -- Log the error
        INSERT INTO status_log (user_id, status, modification_date)
        SELECT user_id, 'Inactive', NOW()
        FROM users
        WHERE status = 'Inactive';
        -- Display error message
        SELECT 'An error occurred while deleting inactive users.' AS error_message;
    END;

    START TRANSACTION;

    -- Delete inactive users
    DELETE FROM users WHERE status = 'Inactive';

    -- Log the deletion in the status_log table
    INSERT INTO status_log (user_id, status, modification_date)
    SELECT user_id, 'Inactive', NOW()
    FROM users
    WHERE status = 'Inactive';

    COMMIT;
END $$

DELIMITER ;
